-- ============================================================
-- UACS Sub-Object Code Reference
-- Source: List_of_Sub-Object_Code (as of 2026-05-15)
-- 1,290 total rows (1,262 active, 28 inactive)
-- Compatible with: PostgreSQL, MySQL 8+, SQLite
-- ============================================================

-- Drop and recreate
DROP TABLE IF EXISTS uacs_codes;

CREATE TABLE uacs_codes (
    id            SERIAL PRIMARY KEY,        -- use INTEGER PRIMARY KEY AUTOINCREMENT for SQLite
    uacs          VARCHAR(10)  NOT NULL UNIQUE,
    label         VARCHAR(255) NOT NULL,     -- most specific display name
    classification VARCHAR(50) NOT NULL,     -- Assets | Liabilities | Equity | Revenue/Income | Expenses
    sub_class     VARCHAR(255),
    grp           VARCHAR(255),              -- "group" is reserved in some dialects
    object_code   VARCHAR(255),
    sub_object_code VARCHAR(255),
    active        BOOLEAN NOT NULL DEFAULT TRUE,
    created_at    TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

-- Indexes for common query patterns
CREATE INDEX idx_uacs_code          ON uacs_codes (uacs);
CREATE INDEX idx_uacs_classification ON uacs_codes (classification);
CREATE INDEX idx_uacs_active        ON uacs_codes (active);
CREATE INDEX idx_uacs_prefix        ON uacs_codes (LEFT(uacs, 4));  -- remove LEFT() for SQLite: use substr()

-- ── INSERT DATA ──

-- ============================================================
-- HANDY VIEWS
-- ============================================================

-- Active codes only (most common use case)
CREATE OR REPLACE VIEW uacs_active AS
  SELECT * FROM uacs_codes WHERE active = TRUE;

-- PS codes (Personnel Services) — 5020xxxxx
CREATE OR REPLACE VIEW uacs_ps AS
  SELECT * FROM uacs_codes
  WHERE active = TRUE AND uacs LIKE '5020%';

-- MOOE codes — 5021xxxxx
CREATE OR REPLACE VIEW uacs_mooe AS
  SELECT * FROM uacs_codes
  WHERE active = TRUE AND uacs LIKE '5021%';

-- CO codes (Capital Outlay) — 506xxxxx
CREATE OR REPLACE VIEW uacs_co AS
  SELECT * FROM uacs_codes
  WHERE active = TRUE AND uacs LIKE '506%';

-- Summary count by classification
CREATE OR REPLACE VIEW uacs_summary AS
  SELECT
    classification,
    COUNT(*) FILTER (WHERE active = TRUE)  AS active_count,
    COUNT(*) FILTER (WHERE active = FALSE) AS inactive_count,
    COUNT(*) AS total
  FROM uacs_codes
  GROUP BY classification
  ORDER BY classification;

